   193→// executeLLMExecBranch executes an LLM-based code generation branch
   194→func (o *fanoutOrchestrator) executeLLMExecBranch(ctx context.Context, branch BranchSpec, result BranchResult) BranchResult {
   195→	// Step 1: Render LLM exec assets
   196→	hclPath, err := o.runner.RenderLLMExecAssets(branch.ID)
   197→	if err != nil {
   198→		result.Status = "failed"
   199→		result.Notes = fmt.Sprintf("failed to render LLM exec assets: %v", err)
   200→		result.FinishedAt = time.Now()
   201→		result.Duration = time.Since(result.StartedAt)
   202→		return result
   203→	}
   204→
   205→	// Step 2: Generate unique run ID for this branch
   206→	runID := fmt.Sprintf("llm-exec-%s-%d", branch.ID, time.Now().Unix())
   207→
   208→	// Step 3: Extract MCP configuration from branch inputs
   209→	var mcpConfig *MCPConfig = nil
   210→	if mcpData, ok := branch.Inputs["mcp_config"]; ok {
   211→		if mcpConfigMap, ok := mcpData.(map[string]interface{}); ok {
   212→			// Convert map to MCPConfig struct
   213→			if parsedMCP, err := parseMCPFromInputs(mcpConfigMap); err == nil {
   214→				mcpConfig = parsedMCP
   215→			}
   216→		}
   217→	}
   218→
   219→	// Step 4: Substitute environment variables in HCL template with MCP support
   220→	renderedHCLPath, err := substituteHCLTemplateWithMCP(hclPath, runID, mcpConfig)
   221→	if err != nil {
   222→		result.Status = "failed"
   223→		result.Notes = fmt.Sprintf("failed to substitute HCL template: %v", err)
   224→		result.FinishedAt = time.Now()
   225→		result.Duration = time.Since(result.StartedAt)
   226→		return result
   227→	}
   228→
   229→	// Step 4: Submit job to Nomad and wait for completion
   230→	timeout := 30 * time.Minute
   231→	if err := orchestration.SubmitAndWaitTerminal(renderedHCLPath, timeout); err != nil {
   232→		result.Status = "failed"
   233→		result.Notes = fmt.Sprintf("LLM exec job failed: %v", err)
   234→		result.FinishedAt = time.Now()
   235→		result.Duration = time.Since(result.StartedAt)
   236→		return result
   237→	}
   238→
   239→	// Step 5: Check for generated diff.patch artifact
   240→	diffPath := filepath.Join(filepath.Dir(renderedHCLPath), "out", "diff.patch")
   241→	if _, err := os.Stat(diffPath); err != nil {
   242→		result.Status = "failed"
   243→		result.Notes = fmt.Sprintf("LLM exec job completed but no diff.patch found: %v", err)
   244→		result.FinishedAt = time.Now()
   245→		result.Duration = time.Since(result.StartedAt)
   246→		return result
   247→	}
   248→
   249→	result.Status = "completed"
   250→	result.Notes = fmt.Sprintf("LLM exec job completed successfully, diff.patch at: %s", diffPath)
   251→	result.FinishedAt = time.Now()
   252→	result.Duration = time.Since(result.StartedAt)
   253→	return result
   254→}
