   256→// parseMCPFromInputs converts map[string]interface{} to MCPConfig struct
   257→func parseMCPFromInputs(inputs map[string]interface{}) (*MCPConfig, error) {
   258→	config := &MCPConfig{}
   259→
   260→	// Parse tools
   261→	if toolsData, ok := inputs["tools"]; ok {
   262→		if toolsList, ok := toolsData.([]interface{}); ok {
   263→			for _, toolData := range toolsList {
   264→				if toolMap, ok := toolData.(map[string]interface{}); ok {
   265→					tool := MCPTool{}
   266→					if name, ok := toolMap["name"].(string); ok {
   267→						tool.Name = name
   268→					}
   269→					if endpoint, ok := toolMap["endpoint"].(string); ok {
   270→						tool.Endpoint = endpoint
   271→					}
   272→					if configData, ok := toolMap["config"].(map[string]interface{}); ok {
   273→						tool.Config = make(map[string]string)
   274→						for k, v := range configData {
   275→							if vStr, ok := v.(string); ok {
   276→								tool.Config[k] = vStr
   277→							}
   278→						}
   279→					}
   280→					config.Tools = append(config.Tools, tool)
   281→				}
   282→			}
   283→		}
   284→	}
   285→
   286→	// Parse context
   287→	if contextData, ok := inputs["context"]; ok {
   288→		if contextList, ok := contextData.([]interface{}); ok {
   289→			for _, ctxData := range contextList {
   290→				if ctxStr, ok := ctxData.(string); ok {
   291→					config.Context = append(config.Context, ctxStr)
   292→				}
   293→			}
   294→		}
   295→	}
   296→
   297→	// Parse prompts
   298→	if promptsData, ok := inputs["prompts"]; ok {
   299→		if promptsList, ok := promptsData.([]interface{}); ok {
   300→			for _, promptData := range promptsList {
   301→				if promptStr, ok := promptData.(string); ok {
   302→					config.Prompts = append(config.Prompts, promptStr)
   303→				}
   304→			}
   305→		}
   306→	}
   307→
   308→	// Parse model
   309→	if model, ok := inputs["model"].(string); ok {
   310→		config.Model = model
   311→	}
   312→
   313→	// Parse budgets
   314→	if budgetsData, ok := inputs["budgets"]; ok {
   315→		if budgetsMap, ok := budgetsData.(map[string]interface{}); ok {
   316→			if maxTokens, ok := budgetsMap["max_tokens"].(int); ok {
   317→				config.Budgets.MaxTokens = maxTokens
   318→			}
   319→			if maxCost, ok := budgetsMap["max_cost"].(int); ok {
   320→				config.Budgets.MaxCost = maxCost
   321→			}
   322→			if timeout, ok := budgetsMap["timeout"].(string); ok {
   323→				config.Budgets.Timeout = timeout
   324→			}
   325→		}
   326→	}
   327→
   328→	return config, nil
   329→}
