   331→// executeORWGenBranch executes an OpenRewrite recipe generation and application branch
   332→func (o *fanoutOrchestrator) executeORWGenBranch(ctx context.Context, branch BranchSpec, result BranchResult) BranchResult {
   333→	// Step 1: Render ORW apply assets
   334→	hclPath, err := o.runner.RenderORWApplyAssets(branch.ID)
   335→	if err != nil {
   336→		result.Status = "failed"
   337→		result.Notes = fmt.Sprintf("failed to render ORW apply assets: %v", err)
   338→		result.FinishedAt = time.Now()
   339→		result.Duration = time.Since(result.StartedAt)
   340→		return result
   341→	}
   342→
   343→	// Step 2: Read HCL template and substitute recipe-specific variables
   344→	hclBytes, err := os.ReadFile(hclPath)
   345→	if err != nil {
   346→		result.Status = "failed"
   347→		result.Notes = fmt.Sprintf("failed to read ORW HCL template: %v", err)
   348→		result.FinishedAt = time.Now()
   349→		result.Duration = time.Since(result.StartedAt)
   350→		return result
   351→	}
   352→
   353→	// Get recipe configuration from branch inputs
   354→	rclass := ""
   355→	rcoords := ""
   356→	rtimeout := "10m"
   357→
   358→	if inputs, ok := branch.Inputs["recipe_config"].(map[string]interface{}); ok {
   359→		if class, ok := inputs["class"].(string); ok {
   360→			rclass = class
   361→		}
   362→		if coords, ok := inputs["coords"].(string); ok {
   363→			rcoords = coords
   364→		}
   365→		if timeout, ok := inputs["timeout"].(string); ok {
   366→			rtimeout = timeout
   367→		}
   368→	}
   369→
   370→	// Perform recipe-specific substitution
   371→	rendered := strings.NewReplacer(
   372→		"${RECIPE_CLASS}", rclass,
   373→		"${RECIPE_COORDS}", rcoords,
   374→		"${RECIPE_TIMEOUT}", rtimeout,
   375→	).Replace(string(hclBytes))
   376→
   377→	// Write substituted HCL to a new file
   378→	renderedHCLPath := strings.ReplaceAll(hclPath, ".rendered.hcl", ".rendered.submitted.hcl")
   379→	if err := os.WriteFile(renderedHCLPath, []byte(rendered), 0644); err != nil {
   380→		result.Status = "failed"
   381→		result.Notes = fmt.Sprintf("failed to write substituted ORW HCL: %v", err)
   382→		result.FinishedAt = time.Now()
   383→		result.Duration = time.Since(result.StartedAt)
   384→		return result
   385→	}
   386→
   387→	// Step 3: Submit job to Nomad and wait for completion
   388→	timeout := 30 * time.Minute
   389→	if err := orchestration.SubmitAndWaitTerminal(renderedHCLPath, timeout); err != nil {
   390→		result.Status = "failed"
   391→		result.Notes = fmt.Sprintf("ORW apply job failed: %v", err)
   392→		result.FinishedAt = time.Now()
   393→		result.Duration = time.Since(result.StartedAt)
   394→		return result
   395→	}
   396→
   397→	// Step 4: Check for generated diff.patch artifact
   398→	diffPath := filepath.Join(filepath.Dir(renderedHCLPath), "out", "diff.patch")
   399→	if _, err := os.Stat(diffPath); err != nil {
   400→		result.Status = "failed"
   401→		result.Notes = fmt.Sprintf("ORW apply job completed but no diff.patch found: %v", err)
   402→		result.FinishedAt = time.Now()
   403→		result.Duration = time.Since(result.StartedAt)
   404→		return result
   405→	}
   406→
   407→	result.Status = "completed"
   408→	result.Notes = fmt.Sprintf("ORW apply job completed successfully, diff.patch at: %s", diffPath)
   409→	result.FinishedAt = time.Now()
   410→	result.Duration = time.Since(result.StartedAt)
   411→	return result
   412→}
